var TWO_PI = 6.283;
var GOLDEN_RATIO = 1.618;
var INV_SQRT2 = 0.707;

var physicsConfig = {
  repulsionStrength: 4000,
  springStiffness: 0.004,
  velocityDamping: 0.92,
  centerGravity: 0.0003,
  maxParticles: 40,
  particleDrag: 0.04,
  cameraSmoothing: 0.06
};

var hubNode = { id: 'hub', label: 'Nexus', r: 26, x: 400, y: 300, vx: 0, vy: 0 };
var alphaNode = { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 };
var betaNode = { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 };
var gammaNode = { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 };
var deltaNode = { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 };
var epsilonNode = { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 };

var nodes = [hubNode, alphaNode, betaNode, gammaNode, deltaNode, epsilonNode];

var springs = [
  { a: 'hub', b: 'alpha', restLength: 160, stiffness: 0.006 },
  { a: 'hub', b: 'beta', restLength: 160, stiffness: 0.005 },
  { a: 'hub', b: 'gamma', restLength: 170, stiffness: 0.004 },
  { a: 'hub', b: 'delta', restLength: 170, stiffness: 0.004 },
  { a: 'hub', b: 'epsilon', restLength: 180, stiffness: 0.003 },
  { a: 'alpha', b: 'beta', restLength: 200, stiffness: 0.002 },
  { a: 'gamma', b: 'delta', restLength: 220, stiffness: 0.002 },
  { a: 'alpha', b: 'epsilon', restLength: 200, stiffness: 0.002 }
];

var currentCamera = { x: 400, y: 300, zoom: 1 };
var targetCamera = { x: 400, y: 300, zoom: 1 };

var particles = [];
var tickCount = 0;

function findNodeById(nodeId) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === nodeId) return nodes[i];
  }
  return null;
}

function applyForces() {
  // Coulomb repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var distance = Math.sqrt(dx * dx + dy * dy) || 1;
      var repulsionForce = physicsConfig.repulsionStrength / (distance * distance);
      var forceX = (dx / distance) * repulsionForce;
      var forceY = (dy / distance) * repulsionForce;

      nodes[i].vx += forceX;
      nodes[i].vy += forceY;
      nodes[j].vx -= forceX;
      nodes[j].vy -= forceY;
    }
  }

  // Hooke's law spring forces along edges
  for (var s = 0; s < springs.length; s++) {
    var nodeA = findNodeById(springs[s].a);
    var nodeB = findNodeById(springs[s].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var distance = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = distance - springs[s].restLength;
    var springForce = (springs[s].stiffness || physicsConfig.springStiffness) * displacement;

    nodeA.vx += (dx / distance) * springForce;
    nodeA.vy += (dy / distance) * springForce;
    nodeB.vx -= (dx / distance) * springForce;
    nodeB.vy -= (dy / distance) * springForce;
  }

  // Integrate velocity, apply damping, and center gravity
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * physicsConfig.centerGravity;
    nodes[n].vy += (300 - nodes[n].y) * physicsConfig.centerGravity;
    nodes[n].vx *= physicsConfig.velocityDamping;
    nodes[n].vy *= physicsConfig.velocityDamping;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

function emitParticle() {
  if (particles.length >= physicsConfig.maxParticles) return;

  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var emitAngle = Math.random() * TWO_PI;
  var emitSpeed = 0.3 + Math.random() * INV_SQRT2;

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(emitAngle) * emitSpeed,
    vy: Math.sin(emitAngle) * emitSpeed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * GOLDEN_RATIO) * INV_SQRT2
  });
}

function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var particle = particles[i];
    particle.age++;
    if (particle.age > particle.maxAge) {
      particles.splice(i, 1);
      continue;
    }
    particle.vx *= 1 - physicsConfig.particleDrag * 0.125;
    particle.vy *= 1 - physicsConfig.particleDrag * 0.125;
    particle.x += particle.vx;
    particle.y += particle.vy;
  }
}

function updateCamera() {
  currentCamera.x += (targetCamera.x - currentCamera.x) * physicsConfig.cameraSmoothing;
  currentCamera.y += (targetCamera.y - currentCamera.y) * physicsConfig.cameraSmoothing;
  currentCamera.zoom += (targetCamera.zoom - currentCamera.zoom) * physicsConfig.cameraSmoothing;
}

function simulationTick() {
  applyForces();
  updateParticles();
  updateCamera();
  if (tickCount % 3 === 0) emitParticle();
  tickCount++;
}

setInterval(simulationTick, 16);
